var GaniVesperes1part = '<p class="psalms1">Tev himnu dziedam, svētais vīr,<br>tu tikumības paraugs spilgts,<br>jo tas, kas tevi cildina,<br>dod godu Dievam debesīs.</p><p class="psalms2">Kungs Kristus, Augstais Priesteris,<br>no nāves ļaudis izglāba,<br>ar Dievu samierināja<br>un deva Jauno Derību.</p><p class="psalms1">Pats tevi izvēlējās Viņš<br>par žēlastības kalpu mums,<br>kas ļaudīm dotu dzīvību<br>un Tēvu pagodinātu.</p><p class="psalms2">' ;
